v.link('graph_edges', {
  ...nodes.via(eq('graph_edges.src', 'graph_nodes.id'), centre).pick({ x1: 'cx', y1: 'cy' }),
  ...nodes.via(eq('graph_edges.dst', 'graph_nodes.id'), centre).pick({ x2: 'cx', y2: 'cy' }),
  stroke: '#b6bdc9',
});
// the label borrows each box's SOLVED geometry from the rect plot (a via on id) and centres in it —
